RATE_LIMIT_STORE: Dict[str, list] = {}
RATE_LIMIT_MAX_REQUESTS = 100
RATE_LIMIT_WINDOW_SECONDS = 3600


def generate_api_key(tenant_id: str) -> str:
    """Generate a secure API key for a tenant."""
    raw_key = uuid.uuid4().hex + uuid.uuid4().hex
    key_hash = hashlib.sha256(raw_key.encode()).hexdigest()
    API_KEYS_STORE[key_hash] = {
        'tenant_id': tenant_id,
        'created_at': datetime.utcnow().isoformat(),
        'active': True,
    }
    return raw_key


def verify_api_key(raw_key: str) -> Optional[Dict[str, Any]]:
    """Verify an API key and return tenant info."""
    if not raw_key or not isinstance(raw_key, str):
        return None
    key_hash = hashlib.sha256(raw_key.encode()).hexdigest()
    key_info = API_KEYS_STORE.get(key_hash)
    if key_info and key_info.get('active'):
        return key_info
    return None


def check_rate_limit(tenant_id: str) -> bool:
    """Check if tenant has exceeded rate limit."""
    now = datetime.utcnow()
    window_start = now - timedelta(seconds=RATE_LIMIT_WINDOW_SECONDS)

    if tenant_id not in RATE_LIMIT_STORE:
        RATE_LIMIT_STORE[tenant_id] = []

    # Clean old entries
    RATE_LIMIT_STORE[tenant_id] = [
        ts for ts in RATE_LIMIT_STORE[tenant_id]
        if ts > window_start
    ]

    if len(RATE_LIMIT_STORE[tenant_id]) >= RATE_LIMIT_MAX_REQUESTS:
        return False

    RATE_LIMIT_STORE[tenant_id].append(now)
    return True


def require_auth(f):
    """Authentication decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header[7:]
        tenant_info = verify_api_key(token)
        if not tenant_info:
            return jsonify({'error': 'Invalid or inactive API key'}), 401

        tenant_id = tenant_info['tenant_id']

        if not check_rate_limit(tenant_id):
            return jsonify({'error': 'Rate limit exceeded'}), 429

        g.tenant_id = tenant_id
        return f(*args, **kwargs)
    return decorated_function


def validate_file_extension(filename: str) -> bool:
    """Validate file has an allowed extension."""
    if not filename:
        return False
    _, ext = os.path.splitext(filename.lower())
    return ext in ALLOWED_EXTENSIONS


def get_tenant_model_dir(tenant_id: str) -> str:
    """Get the model directory for a specific tenant with path traversal protection."""
    safe_tenant_id = secure_filename(tenant_id)
    if not safe_tenant_id:
        raise ValueError("Invalid tenant ID")
    tenant_dir = os.path.join(app.config['UPLOAD_FOLDER'], safe_tenant_id)
    # Verify the resolved path is within the upload folder
    real_upload = os.path.realpath(app.config['UPLOAD_FOLDER'])
    real_tenant = os.path.realpath(tenant_dir)
    if not real_tenant.startswith(real_upload + os.sep) and real_tenant != real_upload:
        raise ValueError("Path traversal detected")
    os.makedirs(tenant_dir, exist_ok=True)
    return tenant_dir


def safe_load_model(file_path: str):
    """
    Securely load a model using skops instead of pickle.
    
    SECURITY: We NEVER use pickle.load() for untrusted data because it allows
    arbitrary code execution during deserialization. Instead, we use skops.io
    which provides safe deserialization with type allowlisting.
    
    The skops library inspects the serialized object tree and only allows
    deserialization of explicitly trusted types, preventing code execution attacks.
    """
    # First, get the list of untrusted types in the file WITHOUT loading it
    try:
        untrusted_types = get_untrusted_types(file=file_path)
    except Exception as e:
        raise ValueError(f"Failed to inspect model file: {str(e)}")

    # Convert untrusted types to their string representations for checking
    untrusted_type_names = set()
    for t in untrusted_types:
        type_name = f"{t.__module__}.{t.__qualname__}"
        untrusted_type_names.add(type_name)

    # Check ALL types against our strict allowlist
    disallowed_types = untrusted_type_names - ALLOWED_MODEL_TYPES
    if disallowed_types:
        raise ValueError(
            f"Model contains disallowed types: {disallowed_types}. "
            f"Only the following types are permitted: {ALLOWED_MODEL_TYPES}"
        )

    # Only load if all types are in our allowlist
    try:
        model = sio.load(file_path, trusted=untrusted_types)
    except Exception as e:
        raise ValueError(f"Failed to load model: {str(e)}")

    # Verify the loaded object has a predict method (is a valid model/pipeline)
    if not hasattr(model, 'predict') and not hasattr(model, 'transform'):
        raise ValueError("Loaded object is not a valid model (no predict or transform method)")

    return model


def compute_file_hash(file_path: str) -> str:
    """Compute SHA-256 hash of a file for integrity verification."""
    sha256_hash = hashlib.sha256()
    with open(file_path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            sha256_hash.update(chunk)
    return sha256_hash.hexdigest()


@app.route('/api/v1/models', methods=['POST'])
@require_auth
def upload_model():
    """
    Upload a model file for the authenticated tenant.
    
    Only accepts .skops format files (skops serialization format).
    Models serialized with pickle are NOT accepted for security reasons.
    """
    tenant_id = g.tenant_id

    if 'model_file' not in request.files:
        return jsonify({'error': 'No model_file in request'}), 400

    file = request.files['model_file']
    model_name = request.form.get('model_name', '').strip()

    if not model_name or len(model_name) > 128:
        return jsonify({'error': 'model_name is required and must be <= 128 characters'}), 400

    # Sanitize model name
    safe_model_name = secure_filename(model_name)
    if not safe_model_name:
        return jsonify({'error': 'Invalid model name'}), 400

    if not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    if not validate_file_extension(file.filename):
        return jsonify({
            'error': f'Invalid file type. Only {list(ALLOWED_EXTENSIONS)} files are accepted. '
                     'Models must be serialized using skops.io for security.'
        }), 400

    try:
        tenant_dir = get_tenant_model_dir(tenant_id)
    except ValueError as e:
        return jsonify({'error': str(e)}), 400

    model_id = uuid.uuid4().hex
    safe_filename_str = f"{model_id}.skops"
    file_path = os.path.join(tenant_dir, safe_filename_str)

    # Verify path is still within tenant directory
    real_tenant_dir = os.path.realpath(tenant_dir)
    real_file_path = os.path.realpath(file_path)
    if not real_file_path.startswith(real_tenant_dir + os.sep):
        return jsonify({'error': 'Invalid file path'}), 400

    # Save to a temporary file first, then validate
    temp_fd, temp_path = tempfile.mkstemp(suffix='.skops', dir=tenant_dir)
    try:
        with os.fdopen(temp_fd, 'wb') as temp_file:
            # Read in chunks to prevent memory issues
            chunk_size = 8192
            total_size = 0
            while True:
                chunk = file.read(chunk_size)
                if not chunk:
                    break
                total_size += len(chunk)
                if total_size > app.config['MAX_CONTENT_LENGTH']:
                    raise ValueError("File too large")
                temp_file.write(chunk)

        # Validate the model can be safely loaded
        model = safe_load_model(temp_path)

        # Compute file hash for integrity
        file_hash = compute_file_hash(temp_path)

        # Move validated file to final location
        shutil.move(temp_path, file_path)

        # Store model metadata (tenant-scoped)
        model_key = f"{tenant_id}:{model_id}"
        MODELS_STORE[model_key] = {
            'model_id': model_id,
            'tenant_id': tenant_id,
            'model_name': safe_model_name,
            'file_path': file_path,
            'file_hash': file_hash,
            'uploaded_at': datetime.utcnow().isoformat(),
            'model_type': type(model).__name__,
        }

        app.logger.info(
            "Model uploaded successfully - tenant: %s, model_id: %s, type: %s",
            tenant_id, model_id, type(model).__name__
        )

        return jsonify({
            'model_id': model_id,
            'model_name': safe_model_name,
            'model_type': type(model).__name__,
            'file_hash': file_hash,
            'message': 'Model uploaded and validated successfully',
        }), 201

    except ValueError as e:
        app.logger.warning(
            "Model validation failed - tenant: %s, error: %s",
            tenant_id, str(e)
        )
        return jsonify({'error': f'Model validation failed: {str(e)}'}), 400
    except Exception as e:
        app.logger.error(
            "Model upload error - tenant: %s, error: %s",
            tenant_id, str(e)
        )
        return jsonify({'error': 'Internal error during model upload'}), 500
    finally:
        # Clean up temp file if it still exists
        if os.path.exists(temp_path):
            os.unlink(temp_path)


@app.route('/api/v1/models/<model_id>/predict', methods=['POST'])
@require_auth
def predict(model_id: str):
    """Run inference using a tenant's uploaded model."""
    tenant_id = g.tenant_id

    # Sanitize model_id
    safe_model_id = secure_filename(model_id)
    if not safe_model_id or safe_model_id != model_id:
        return jsonify({'error': 'Invalid model ID'}), 400

    # Tenant-scoped model lookup (prevents cross-tenant access)
    model_key = f"{tenant_id}:{model_id}"
    model_info = MODELS_STORE.get(model_key)

    if not model_info:
        return jsonify({'error': 'Model not found'}), 404

    # Verify tenant ownership (defense in depth)
    if model_info['tenant_id'] != tenant_id:
        return jsonify({'error': 'Model not found'}), 404

    # Parse input data
    if not request.is_json:
        return jsonify({'error': 'Request must be JSON'}), 400

    data = request.get_json(silent=True)
    if data is None:
        return jsonify({'error': 'Invalid JSON'}), 400

    input_data = data.get('input')
    if input_data is None:
        return jsonify({'error': 'Missing "input" field'}), 400

    if not isinstance(input_data, list):
        return jsonify({'error': '"input" must be a list of samples'}), 400

    # Limit input size
    if len(input_data) > 10000:
        return jsonify({'error': 'Maximum 10000 samples per request'}), 400

    try:
        # Validate input data contains only numbers
        input_array = np.array(input_data, dtype=np.float64)
        if not np.all(np.isfinite(input_array)):
            return jsonify({'error': 'Input contains non-finite values (NaN/Inf)'}), 400
    except (ValueError, TypeError):
        return jsonify({'error': 'Input data must contain only numeric values'}), 400

    file_path = model_info['file_path']

    # Verify file integrity before loading
    current_hash = compute_file_hash(file_path)
    if current_hash != model_info['file_hash']:
        app.logger.error(
            "Model file integrity check failed - tenant: %s, model_id: %s",
            tenant_id, model_id
        )
        return jsonify({'error': 'Model integrity check failed'}), 500

    try:
        model = safe_load_model(file_path)
        predictions = model.predict(input_array)
        result = predictions.tolist() if hasattr(predictions, 'tolist') else list(predictions)

        return jsonify({
            'model_id': model_id,
            'predictions': result,
            'num_samples': len(input_data),
        }), 200

    except ValueError as e:
        return jsonify({'error': f'Prediction error: {str(e)}'}), 400
    except Exception as e:
        app.logger.error(
            "Prediction error - tenant: %s, model_id: %s, error: %s",
            tenant_id, model_id, str(e)
        )
        return jsonify({'error': 'Internal error during prediction'}), 500


@app.route('/api/v1/models', methods=['GET'])
@require_auth
def list_models():
    """List all models for the authenticated tenant."""
    tenant_id = g.tenant_id

    tenant_models = []
    for key, info in MODELS_STORE.items():
        if info['tenant_id'] == tenant_id:
            tenant_models.append({
                'model_id': info['model_id'],
                'model_name': info['model_name'],
                'model_type': info['model_type'],
                'uploaded_at': info['uploaded_at'],
            })

    return jsonify({'models': tenant_models}), 200


@app.route('/api/v1/models/<model_id>', methods=['DELETE'])
@require_auth
def delete_model(model_id: str):
    """Delete a model for the authenticated tenant."""
    tenant_id = g.tenant_id

    safe_model_id = secure_filename(model_id)
    if not safe_model_id or safe_model_id != model_id:
        return jsonify({'error': 'Invalid model ID'}), 400

    model_key = f"{tenant_id}:{model_id}"
    model_info = MODELS_STORE.get(model_key)

    if not model_info:
        return jsonify({'error': 'Model not found'}), 404

    if model_info['tenant_id'] != tenant_id:
        return jsonify({'error': 'Model not found'}), 404

    # Delete file
    file_path = model_info['file_path']
    if os.path.exists(file_path):
        os.unlink(file_path)

    del MODELS_STORE[model_key]

    app.logger.info(
        "Model deleted - tenant: %s, model_id: %s",
        tenant_id, model_id
    )

    return jsonify({'message': 'Model deleted successfully'}), 200


