# Admin endpoint for key generation (in production, this would be a separate admin service)
@app.route('/admin/api-keys', methods=['POST'])
def create_api_key():
    """Create an API key for a tenant. In production, protect with admin auth."""
    admin_token = request.headers.get('X-Admin-Token', '')
    expected_admin_token = os.environ.get('ADMIN_TOKEN')

    if not expected_admin_token:
        return jsonify({'error': 'Admin endpoint not configured'}), 503

    if not hmac.compare_digest(admin_token, expected_admin_token):
        return jsonify({'error': 'Unauthorized'}), 401

    data = request.get_json(silent=True)
    if not data or 'tenant_id' not in data:
        return jsonify({'error': 'tenant_id is required'}), 400

    tenant_id = str(data['tenant_id']).strip()
    if not tenant_id or len(tenant_id) > 64:
        return jsonify({'error': 'Invalid tenant_id'}), 400

    safe_tenant_id = secure_filename(tenant_id)
    if not safe_tenant_id:
        return jsonify({'error': 'Invalid tenant_id'}), 400

    api_key = generate_api_key(safe_tenant_id)

    # Log key creation without exposing the key
    app.logger.info("API key created for tenant: %s", safe_tenant_id)

    return jsonify({
        'tenant_id': safe_tenant_id,
        'api_key': api_key,
        'message': 'Store this API key securely. It cannot be retrieved again.',
    }), 201


